# Deobfuscated Code

Let me work through this step by step.

## Step 1: Resolve the String Table

The code uses a rotating string array (`a0_0x111f`) with base64-encoded entries and a lookup function (`a0_0x3e56`). After decoding all the string references, here's the fully deobfuscated code:

```javascript
// Constants
var TAU = 6.283;          // 2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // √(1/2)

// Physics configuration
var config = {
  fieldStrength: 4000,      // Coulomb repulsion magnitude
  elasticModulus: 0.004,    // Spring stiffness (default for edges)
  convergenceRate: 0.92,    // Velocity damping per tick
  orbitalDecay: 0.0003,     // Center-seeking gravity force
  particleCeiling: 40,      // Max number of sea particles
  streamDecay: 0.04,        // Particle drag/friction
  theta: 0.06               // Camera interpolation speed
};

// === NODES ===
var nodes = [
  { id: "hub",      label: "Kieleth", r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",    label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",     label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",    label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",    label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon",  label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// === EDGES (springs) ===
// Each edge: { a, b, rest (rest length), k (spring constant) }
var edges = [
  { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub", b: "beta",    rest: 160, k: 0.005 },
  { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub", b: "delta",   rest: 170, k: 0.004 },
  { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// === CAMERA ===
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// === PARTICLES (cosmetic "sea" particles) ===
var particles = [];
var tick = 0;

// --- Helper: find node by ID ---
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// --- Core physics step ---
function physicsStep() {
  // 1) COULOMB REPULSION between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.fieldStrength / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) SPRING ATTRACTION along edges (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.elasticModulus) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) INTEGRATION: damping, gravity toward center (400,300), position update
  for (var n = 0; n < nodes.length; n++) {
    // Center-seeking gravity
    nodes[n].vx += (400 - nodes[n].x) * config.orbitalDecay;
    nodes[n].vy += (300 - nodes[n].y) * config.orbitalDecay;
    // Velocity damping
    nodes[n].vx *= config.convergenceRate;
    nodes[n].vy *= config.convergenceRate;
    // Position update
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// --- Spawn a cosmetic particle ---
function spawnParticle() {
  if (particles.length >= config.particleCeiling) return;
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// --- Update particles ---
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    // Apply drag
    p.vx *= (1 - config.particleCeiling * 0.125);  // Note: uses particleCeiling oddly
    p.vy *= (1 - config.particleCeiling * 0.125);
    // Move
    p.x += p.vx;
    p.y += p.vy;
    // Age and remove
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// --- Smooth camera follow ---
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.theta;
  camera.y += (cameraTarget.y - camera.y) * config.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// --- Main loop ---
function mainLoop() {
  physicsStep();
  updateParticles();
  updateCamera();
  if (tick % 3 === 0) spawnParticle();  // Spawn particle every 3rd tick
  tick++;
}

setInterval(mainLoop, 16);  // ~60fps
```

## What It Does

This is the **simulation engine** (no rendering code) for a **force-directed graph visualization**. Here's the breakdown:

### Graph Structure
A star-like graph centered on a hub node called **"Kieleth"** with 5 leaf nodes (Alpha through Epsilon), connected by 8 spring edges. The hub connects to all leaves, and a few leaves connect to each other.

### Three Forces Act on Each Node Every Tick

| Force | Purpose |
|-------|---------|
| **Coulomb repulsion** | All node pairs repel each other inversely proportional to distance² — prevents overlap |
| **Hooke's law springs** | Connected nodes are pulled toward their rest-length distance — maintains structure |
| **Center gravity** | A weak force pulls everything toward (400, 300) — prevents drift |

Velocities are **damped by 0.92× per tick** (convergenceRate) so the system settles into equilibrium.

### Cosmetic Particles
Every 3rd tick, a particle spawns from a random node, drifts outward at a random angle, ages, and is removed when it expires. These create a decorative "sea" or ambient particle field effect. They have **no effect** on the physics.

### Camera
Smoothly interpolates toward a target position/zoom using linear interpolation at 6% per frame. The target is never changed in this code (would be set by mouse interaction elsewhere).

### The Obfuscation Layers

1. **String array rotation** — a self-unshuffling array with an integrity checksum
2. **Base64-encoded string table** — all property names and string literals are encoded
3. **Control flow flattening** — `switch` statements with string-encoded execution orders like `"4|0|2|3|5|1"` that get split and iterated
4. **Poisoned variable names** — as described in the blog post, the decoded names in the string table are deliberately plausible-but-wrong physics terms (e.g., "attraction" instead of "fieldStrength", "frictionCoeff" instead of "elasticModulus")

The interval runs at **16ms (~60fps)**, making this a real-time physics simulation loop that would be paired with a Canvas 2D renderer (not included in this snippet).
